# ANTI-PATTERN: Naive single-pass retrieval, no re-ranking
class NaiveRetriever:
    def retrieve_batsman_insights(self, query: str):
        """Retrieves top-10 documents, returns as-is. High recall, low precision."""
        embeddings = self.encoder.encode(query)
        scores = self.index.search(embeddings, k=10)
        return scores  # Returns unranked, includes noisy documents

# BEST PRACTICE: Retrieve-Then-Rank with fusion
class ProductionRetriever:
    def retrieve_batsman_insights(self, query: str, budget_ms: int = 200):
        """Two-stage: broad dense retrieval + expensive re-ranking."""
        # Stage 1: Dual retrieval (sparse + dense) - fast
        dense_scores = self.dense_index.search(query, k=50)  # ~20ms
        sparse_scores = self.bm25_index.search(query, k=50)  # ~10ms

        # Normalize and fuse
        fused = self._fuse_scores(dense_scores, sparse_scores, alpha=0.6)
        candidates = self._get_top_k(fused, k=20)  # ~5ms

        # Stage 2: Expensive cross-encoder re-ranking on candidates only
        reranked = self.cross_encoder.score(
            query, 
            candidates,
            batch_size=16  # Parallel scoring
        )  # ~150ms for 20 docs

        return sorted(reranked, key=lambda x: x['score'], reverse=True)

    def _fuse_scores(self, dense, sparse, alpha=0.6):
        """Weighted combination: semantic + lexical signals."""
        return {doc_id: alpha * dense.get(doc_id, 0) + (1-alpha) * sparse.get(doc_id, 0)
                for doc_id in set(dense.keys()) | set(sparse.keys())}

    def _get_top_k(self, scores_dict, k):
        return sorted(scores_dict.items(), key=lambda x: x[1], reverse=True)[:k]
